// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

/**
 * @title SACCODirectorElection
 * @dev A smart contract for SACCO director elections.
 * The admin registers candidates and qualified delegates.
 * Delegates can vote once per position during the active election period.
 */
contract SACCODirectorElection {
    address public admin;
    bool public electionOpen;
    uint256 public votingDeadline;

    uint256 private nextCandidateId = 1;
    string[] private positionList;

    struct Delegate {
        bool isRegistered;
        string name;
        string membershipNumber;
    }

    struct Candidate {
        uint256 id;
        string name;
        string membershipNumber;
        string position;
        uint256 voteCount;
        bool isActive;
    }

    mapping(address => Delegate) public delegates;
    mapping(uint256 => Candidate) public candidates;
    mapping(string => uint256[]) private candidatesByPosition;

    // Tracks whether a delegate has voted for a specific position
    mapping(address => mapping(string => bool)) private hasVotedForPosition;

    event DelegateRegistered(
        address indexed delegateAddress,
        string name,
        string membershipNumber
    );

    event CandidateRegistered(
        uint256 indexed candidateId,
        string name,
        string membershipNumber,
        string position
    );

    event CandidateDeactivated(uint256 indexed candidateId);
    event ElectionOpened(uint256 deadline);
    event ElectionClosed(uint256 closedAt);

    event VoteCast(
        address indexed delegateAddress,
        uint256 indexed candidateId,
        string position
    );

    event AdminTransferred(
        address indexed oldAdmin,
        address indexed newAdmin
    );

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin can perform this action");
        _;
    }

    modifier onlyWhenOpen() {
        require(electionOpen, "Election is not open");
        require(block.timestamp < votingDeadline, "Voting deadline has passed");
        _;
    }

    modifier onlyWhenClosed() {
        require(
            !electionOpen || block.timestamp >= votingDeadline,
            "Election is still ongoing"
        );
        _;
    }

    constructor() {
        admin = msg.sender;
    }

    /**
     * @dev Register a qualified delegate who can vote.
     */
    function registerDelegate(
        address delegateAddress,
        string memory name,
        string memory membershipNumber
    ) external onlyAdmin {
        require(delegateAddress != address(0), "Invalid delegate address");
        require(!delegates[delegateAddress].isRegistered, "Delegate already registered");
        require(bytes(name).length > 0, "Delegate name cannot be empty");
        require(bytes(membershipNumber).length > 0, "Membership number cannot be empty");
        require(!electionOpen, "Cannot register delegates while election is open");

        delegates[delegateAddress] = Delegate({
            isRegistered: true,
            name: name,
            membershipNumber: membershipNumber
        });

        emit DelegateRegistered(delegateAddress, name, membershipNumber);
    }

    /**
     * @dev Register a candidate for a SACCO position.
     * Example positions: Chairperson, Treasurer, Director
     */
    function registerCandidate(
        string memory name,
        string memory membershipNumber,
        string memory position
    ) external onlyAdmin {
        require(bytes(name).length > 0, "Candidate name cannot be empty");
        require(bytes(membershipNumber).length > 0, "Membership number cannot be empty");
        require(bytes(position).length > 0, "Position cannot be empty");
        require(!electionOpen, "Cannot register candidates while election is open");

        uint256 candidateId = nextCandidateId;

        candidates[candidateId] = Candidate({
            id: candidateId,
            name: name,
            membershipNumber: membershipNumber,
            position: position,
            voteCount: 0,
            isActive: true
        });

        candidatesByPosition[position].push(candidateId);

        // add position to positionList only once
        bool exists = false;
        for (uint256 i = 0; i < positionList.length; i++) {
            if (
                keccak256(bytes(positionList[i])) == keccak256(bytes(position))
            ) {
                exists = true;
                break;
            }
        }
        if (!exists) {
            positionList.push(position);
        }

        nextCandidateId++;

        emit CandidateRegistered(candidateId, name, membershipNumber, position);
    }

    /**
     * @dev Deactivate a candidate before election opens.
     */
    function deactivateCandidate(uint256 candidateId) external onlyAdmin {
        require(candidates[candidateId].id != 0, "Candidate does not exist");
        require(!electionOpen, "Cannot deactivate candidates while election is open");
        require(candidates[candidateId].isActive, "Candidate already inactive");

        candidates[candidateId].isActive = false;

        emit CandidateDeactivated(candidateId);
    }

    /**
     * @dev Open the election for a given number of minutes.
     */
    function openElection(uint256 durationInMinutes) external onlyAdmin {
        require(!electionOpen, "Election already open");
        require(durationInMinutes > 0, "Duration must be greater than zero");

        electionOpen = true;
        votingDeadline = block.timestamp + (durationInMinutes * 1 minutes);

        emit ElectionOpened(votingDeadline);
    }

    /**
     * @dev Close election manually.
     */
    function closeElection() external onlyAdmin {
        require(electionOpen, "Election is not open");
        electionOpen = false;

        emit ElectionClosed(block.timestamp);
    }

    /**
     * @dev Cast one vote for one candidate in a given position.
     * A delegate can vote only once per position.
     */
    function vote(uint256 candidateId) external onlyWhenOpen {
        Delegate memory delegate_ = delegates[msg.sender];
        require(delegate_.isRegistered, "Only registered delegates can vote");

        Candidate storage candidate = candidates[candidateId];
        require(candidate.id != 0, "Candidate does not exist");
        require(candidate.isActive, "Candidate is not active");

        string memory position = candidate.position;

        require(
            !hasVotedForPosition[msg.sender][position],
            "You have already voted for this position"
        );

        hasVotedForPosition[msg.sender][position] = true;
        candidate.voteCount += 1;

        emit VoteCast(msg.sender, candidateId, position);
    }

    /**
     * @dev Returns candidate details.
     */
    function getCandidate(uint256 candidateId)
        external
        view
        returns (
            uint256 id,
            string memory name,
            string memory membershipNumber,
            string memory position,
            uint256 voteCount,
            bool isActive
        )
    {
        Candidate memory c = candidates[candidateId];
        require(c.id != 0, "Candidate does not exist");

        return (
            c.id,
            c.name,
            c.membershipNumber,
            c.position,
            c.voteCount,
            c.isActive
        );
    }

    /**
     * @dev Returns all candidate IDs for a given position.
     */
    function getCandidatesByPosition(string memory position)
        external
        view
        returns (uint256[] memory)
    {
        return candidatesByPosition[position];
    }

    /**
     * @dev Returns all known positions in the election.
     */
    function getAllPositions() external view returns (string[] memory) {
        return positionList;
    }

    /**
     * @dev Returns whether a delegate has voted for a specific position.
     */
    function hasDelegateVotedForPosition(
        address delegateAddress,
        string memory position
    ) external view returns (bool) {
        return hasVotedForPosition[delegateAddress][position];
    }

    /**
     * @dev Returns the winning candidate ID for a given position.
     * Can only be called after election closes or deadline passes.
     */
    function winningCandidate(string memory position)
        public
        view
        onlyWhenClosed
        returns (uint256 winningCandidateId)
    {
        uint256[] memory ids = candidatesByPosition[position];
        require(ids.length > 0, "No candidates for this position");

        uint256 highestVotes = 0;
        uint256 winnerId = 0;

        for (uint256 i = 0; i < ids.length; i++) {
            Candidate memory c = candidates[ids[i]];
            if (c.isActive && c.voteCount > highestVotes) {
                highestVotes = c.voteCount;
                winnerId = c.id;
            }
        }

        require(winnerId != 0, "No winner determined");
        return winnerId;
    }

    /**
     * @dev Returns winner details for a given position.
     */
    function winnerDetails(string memory position)
        external
        view
        onlyWhenClosed
        returns (
            uint256 id,
            string memory name,
            string memory membershipNumber,
            uint256 voteCount
        )
    {
        uint256 winnerId = winningCandidate(position);
        Candidate memory c = candidates[winnerId];

        return (c.id, c.name, c.membershipNumber, c.voteCount);
    }

    /**
     * @dev Returns full results for a specific position.
     */
    function getPositionResults(string memory position)
        external
        view
        returns (
            uint256[] memory candidateIds,
            string[] memory names,
            uint256[] memory voteCounts,
            bool[] memory activeStatuses
        )
    {
        uint256[] memory ids = candidatesByPosition[position];
        uint256 len = ids.length;

        candidateIds = new uint256[](len);
        names = new string[](len);
        voteCounts = new uint256[](len);
        activeStatuses = new bool[](len);

        for (uint256 i = 0; i < len; i++) {
            Candidate memory c = candidates[ids[i]];
            candidateIds[i] = c.id;
            names[i] = c.name;
            voteCounts[i] = c.voteCount;
            activeStatuses[i] = c.isActive;
        }
    }

    /**
     * @dev Returns time left in seconds.
     */
    function timeLeft() external view returns (uint256) {
        if (!electionOpen || block.timestamp >= votingDeadline) {
            return 0;
        }
        return votingDeadline - block.timestamp;
    }

    /**
     * @dev Transfer admin role to another address.
     */
    function transferAdmin(address newAdmin) external onlyAdmin {
        require(newAdmin != address(0), "Invalid new admin address");

        address oldAdmin = admin;
        admin = newAdmin;

        emit AdminTransferred(oldAdmin, newAdmin);
    }
}

